-- BLOCO 1 (parte 3/6) — Revisão linguística pílulas PIII (4 variants pt-BR)

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Acabou. E agora vejo o que não dava pra ver enquanto estava acontecendo.", "tension_label": "Presença ↔ Distância"}, "m2": {"scene": "O projeto durou quatro anos. Helena tinha movido a vida inteira pra fazer dar certo. Era a razão dela. A identidade. A coisa que a acordava de manhã.\n\nNo último dia, teve uma comemoração pequena. Todos agradeceram a todos. Helena ficou na sala e não sentiu nada.\n\nDuas semanas depois, com distância, começou a ver com clareza:\n\nO projeto tinha precisado dela sendo alguém muito específico. Movida. Sacrificial. Capaz de ignorar as partes dela que queriam descanso. A equipe tinha gostado dela porque ela continuava aparecendo nessa forma. E ela tinha ficado nessa forma porque o projeto dava a ela um papel que ela entendia.\n\nAgora, olhando fotos dos quatro anos, conseguia ver o momento exato em que mudou — quando deixou de ser sobre o trabalho e virou sobre provar algo. Quando o sacrifício virou o ponto. Conseguia ver no rosto dela.\n\nA clareza era exata. E o luto também era exato.\n\nEla tinha desperdiçado quatro anos. Ou tinha aprendido algo essencial. Não conseguia dizer qual, e a diferença importava.", "question": "O que Helena estava enlutando mais — o tempo, ou o que tinha aprendido sobre si mesma?"}, "m4": {"question": "O que você está notando sobre a diferença entre como fala disso agora, com clareza, e como viveu enquanto estava acontecendo?", "instruction": "Uma ou duas frases. O que mudou entre o agora e o então — nas próprias palavras?"}, "m3_1": {"context": "Testa se a pessoa vê a distância como revelação (verdade exposta) ou construção (sentido feito depois). Núcleo de PIII — clareza é descoberta ou interpretação.", "question": "Agora que você consegue ver com clareza, a clareza parece mais que está revelando algo que sempre esteve lá, ou que está criando algo novo sobre o que aconteceu?", "pole_left": "Sempre esteve lá", "pole_right": "Estou criando esse entendimento agora"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Continuo com a clareza que tenho e pergunto: o que vejo de fato quando olho pra eles agora? Não quem foram, não quem eu esperava que fossem. Quem são?", "followup": "O que isso revelou?", "followup_type": "question"}, {"key": "B", "text": "Trago quem sou agora. Sou honesto sobre o que vejo e entendo.", "followup": "A simplicidade da relação anterior. A chance de eles não conseguirem lidar com quem você virou.", "followup_type": "cost"}, {"key": "C", "text": "Reconheço a mudança diretamente: somos diferentes. Podemos descobrir o que isso significa?", "followup": "O que tornou possível nomear a mudança em vez de só agir nela?", "followup_type": "question"}, {"key": "D", "text": "Procuro e sigo o que vem deles. Vejo aonde vai.", "followup": "Controle sobre o processo. Clareza sobre se reconectar é de fato possível.", "followup_type": "cost"}], "scenario": "Alguém com quem você foi próximo voltou pra sua vida. A distância entre vocês mudou os dois. Você ainda não sabe se isso é bom ou ruim. Está sendo pedido que você reconcilie com base em quem os dois são agora, não em quem foram antes."}, "m3_3": {"q1": "Lembre de algo que você não conseguia ver enquanto acontecia. Quando finalmente viu, qual foi o primeiro momento de clareza?", "q2": "O que tornou possível finalmente ver?", "scoring_note": "Buscar: o que disparou a clareza? (Distância? Uma conversa? Tempo passando? Um ponto de ruptura?) Resolução de PIII frequentemente depende de entender o que cria a capacidade de ver. É passivo (tempo) ou ativo (escolha)? L1.3 transversal: testar se distância/clareza retroativamente altera o julgamento de qualidade.", "q_transversal": "Agora que você vê com clareza — o que você fez naquele tempo foi bom o suficiente? Ou a clareza muda essa avaliação?"}}$rdwth_final$::jsonb
WHERE id = '312a7be0-468b-44ee-bdc2-b351ea336bdb';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Foi preciso terminar pra eu entender o que aquilo de fato era.", "tension_label": "Presença ↔ Distância"}, "m2": {"scene": "Caio tinha sido casado por dezoito anos. Eram bons parceiros. Responsáveis. Estáveis. Tinham construído algo real.\n\nDaí o cônjuge de Caio foi embora. Foi súbito e não foi súbito — todos viam vindo, exceto Caio, que estava presente mas sem ver.\n\nNos meses seguintes, Caio tinha momentos cortantes de clareza:\n\nO jeito como tinham evitado conflito tão cuidadosamente que tinham evitado honestidade. Como tinham construído conforto em vez de intimidade. Como Caio tinha fingido contentamento enquanto se sentia solitário dentro da relação.\n\nE pior: Caio conseguia ver exatamente quando isso tinha virado verdade. Conseguia identificar o momento (uma noite específica, uma conversa específica). Conseguia ver que tinha tido escolhas no caminho e tinha escolhido o caminho mais fácil cada vez.\n\nO cônjuge de Caio tinha tentado nomear isso. Várias vezes. Caio não tinha ouvido. Ou tinha ouvido e escolhido não responder.\n\nAgora, sozinho, Caio conseguia ver tudo. E a clareza parecia uma crueldade — tarde demais, honesta demais, queimando.", "question": "O que Caio estava sendo forçado a aceitar sobre a própria capacidade de se enganar?"}, "m4": {"question": "Nessa conversa sobre o que você aprendeu e entendeu, quantas vezes você defendeu ou explicou algo que antes culpava?", "instruction": "Conte se conseguir. Em uma frase, o que mudou entre culpar e defender?"}, "m3_1": {"context": "Testa se culpam a si mesmos pela cegueira ou aceitam como condição da presença. Resolução de PIII depende dessa distinção.", "question": "Aquela coisa que você não conseguia ver enquanto acontecia — você teria querido ver se conseguisse? Ou acha que não ver era de fato necessário?", "pole_left": "Eu deveria ter visto", "pole_right": "Eu não conseguiria ter visto"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Pauso e examino: estou protegendo elas, ou estou me protegendo do julgamento delas? Meu silêncio é gentileza ou medo?", "followup": "O que essa distinção mudou?", "followup_type": "question"}, {"key": "B", "text": "Conto a verdade do que entendi.", "followup": "O conforto delas. Possivelmente a relação.", "followup_type": "cost"}, {"key": "C", "text": "Pergunto por que a história antiga importa pra elas.", "followup": "O que você estava tentando entender sobre elas?", "followup_type": "question"}, {"key": "D", "text": "Testo: conto pra elas um pedacinho da verdade e observo como respondem.", "followup": "O que decidiu se você ia contar mais?", "followup_type": "question"}], "scenario": "Você entendeu algo sobre seu passado que muda como entende a si mesmo. É clareza, mas dói. Alguém que você ama não quer ouvir. Gostava da história que você tinha antes. Quer que você mantenha a versão de si mesmo que ela conheceu."}, "m3_3": {"q1": "Desde que você teve essa clareza, o que você teve que enlutar que não esperava enlutar?", "q2": "Esse luto está mudando o que a clareza significa pra você?", "scoring_note": "Testa se conseguem segurar complexidade — clareza mais perda. PIII muitas vezes não é sobre aprender a verdade; é sobre aprender que verdade tem custo. L1.3 transversal: testar se a perda recalibra critérios de suficiência em contextos relacionais.", "q_transversal": "Depois desse luto, você mudou o que considera estar presente o bastante numa relação?"}}$rdwth_final$::jsonb
WHERE id = '68b8531b-78ef-49dd-86b0-bebd2ab0c1b1';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Precisei de distância pra finalmente ver com clareza. Mas agora estou enlutando o que a clareza me mostra.", "tension_label": "Presença ↔ Distância"}, "m2": {"scene": "Sofia tinha trabalhado pro mentor por seis anos. Acreditava nele. Defendia. Construiu a carreira na sombra dele.\n\nTrês meses depois de sair, começou a entender o que tinha visto mas não tinha nomeado: o jeito como ele usava as pessoas, como a posicionava como sucessora enquanto a minava, como a fez cúmplice.\n\nEla tinha estado presente em tudo aquilo. Só era uma versão de si mesma que não conseguia ver.\n\nProcurando uma ex-colega: 'Você viu?' A colega ficou em silêncio. 'Vi muito antes. Tentei te contar.' Sofia sentiu duas coisas: alívio (não estava louca) e vergonha (tinha ignorado o aviso por anos).", "question": "O que Sofia estava protegendo ao ficar incapaz de ver com clareza?"}, "m4": {"question": "A clareza que você tem agora é algo que você precisou ganhar, ou ainda está negociando?", "instruction": "Uma frase ou duas. O que pesa mais agora — o custo da clareza ou a negociação?"}, "m3_1": {"context": "Testa se a distância clarifica ou desestabiliza o significado. PIII frequentemente envolve as duas coisas ao mesmo tempo.", "question": "Agora que você vê com clareza, sente que entende o que aquilo de fato era, ou sente que está enlutando algo que nunca existiu de verdade?", "pole_left": "Entendo o que era", "pole_right": "Estou enlutando uma ilusão"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Mantenho a clareza em particular. Mudo internamente sem contar pra ninguém.", "followup": "Isolamento. A chance de consertar o que você entende agora.", "followup_type": "cost"}, {"key": "B", "text": "Conto pras pessoas envolvidas o que entendo sobre meu papel.", "followup": "O julgamento delas. Controle sobre a interpretação delas do que aconteceu.", "followup_type": "cost"}, {"key": "C", "text": "Peço ajuda pra entender — levo isso pra alguém em quem confio.", "followup": "O que tornou seguro não ter a resposta sozinho?", "followup_type": "question"}, {"key": "D", "text": "Demoro na clareza tempo o bastante pra saber se é entendimento permanente ou dor temporária.", "followup": "Como você vai saber quando entendeu o suficiente?", "followup_type": "question"}], "scenario": "A distância te mostrou algo doloroso sobre você mesmo — o jeito como você contribuiu pra algo que machucou, ou falhou com alguém que importava, ou desperdiçou algo precioso. A clareza é real. E não é mais só sobre eles — é sobre quem você é."}, "m3_3": {"q1": "Qual é uma coisa que parece completamente diferente agora do que parecia de dentro da experiência?", "q2": "Você teria querido saber disso enquanto estava nela, ou a distância é essencial pra aceitar?", "scoring_note": "Revela se veem distância como clarificadora (melhoria) ou destrutiva (perda necessária). A resposta molda como integram a clareza. L1.3 transversal: testar se julgamento retrospectivo altera os critérios originais de suficiência.", "q_transversal": "Ver isso diferente agora muda o que você pensa sobre como fez na época?"}}$rdwth_final$::jsonb
WHERE id = 'a1f0423c-7b41-4aea-a24a-5d5e1bcbd0bf';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "De longe, finalmente vejo a verdade. E não sei o que fazer com ela.", "tension_label": "Presença ↔ Distância"}, "m2": {"scene": "Lucas tinha sido melhor amigo de alguém por uma década. Daí — uma deriva lenta, um conflito, um fim.\n\nMeses depois, Lucas finalmente conseguiu ver a amizade com clareza: tinha sido desigual. Lucas tinha sido menor, querendo menos, acomodando. Tinha tido momentos pra falar, pra renegociar, mas Lucas tinha escolhido ser diminuído em vez de arriscar a relação.\n\nAgora Lucas conseguia ver que tinha estado se traindo por anos. O amigo provavelmente não era o vilão — Lucas só não tinha estado disposto a ser uma pessoa inteira naquela relação. O fim parecia falha de Lucas.", "question": "O que custaria a Lucas parar de culpar o amigo e começar a reconhecer a escolha?"}, "m4": {"question": "O que significaria sobre você se nunca chegasse a uma clareza completa sobre isso — se uma parte sempre ficasse turva?", "instruction": "Seja honesto em uma frase ou duas. Dizer 'consigo conviver com isso' e dizer 'dói' são respostas válidas."}, "m3_1": {"context": "Revela se veem clareza como melhoria ou perda. A resposta é diagnóstica para PIII.", "question": "Se você pudesse voltar e contar pro seu eu do passado o que sabe agora, contaria, ou protegeria seu eu do passado desse conhecimento?", "pole_left": "Eu contaria", "pole_right": "Eu protegeria do saber"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Procuro. Fecho o ciclo.", "followup": "A paz da distância. Controle sobre a reação dela.", "followup_type": "cost"}, {"key": "B", "text": "Fico no silêncio. O que está feito está feito.", "followup": "Reconciliação. Fechamento. Saber se ela te entenderia agora.", "followup_type": "cost"}, {"key": "C", "text": "Examino esse impulso com cuidado: por que quero falar agora? Estou buscando fechamento pra mim, ou buscando algo dela? O que estou esperando que aconteça?", "followup": "O que mudou quando você entendeu suas próprias razões?", "followup_type": "question"}, {"key": "D", "text": "Espero. Se o momento vier naturalmente, falo. Se não, não forço.", "followup": "O que você está fazendo nessa espera?", "followup_type": "question"}], "scenario": "Você ganhou clareza sobre algo que terminou há muito tempo. Anos passaram. Você poderia procurar e endereçar. Ou poderia deixar fechado. Não há razão urgente pra agir. Mas há algo em você que quer."}, "m3_3": {"q1": "Ver com clareza mudou alguma coisa em como você segue em frente, ou mudou só seu entendimento do passado?", "q2": "Qual a diferença entre entender o que aconteceu e saber o que fazer a respeito?", "scoring_note": "Testa se clareza leva à ação ou fica como consciência. Resolução de PIII às vezes significa aceitar que entende mas não pode mudar nada. L1.3 transversal: testar se a clareza altera permanentemente os critérios de suficiência.", "q_transversal": "A clareza mudou alguma coisa em como você mede o que faz daqui pra frente?"}}$rdwth_final$::jsonb
WHERE id = '9016f271-ca74-4e80-933e-af333990315a';